const TranslateBirthCertificate  = ({ data,  confirm }) => {
	
	const frmNm = "birth_certificate"


	let flds = [
		"folio",
		"tomo",
		"state_registration",
		"registration_officer",
		"revised_by",
		"prepared_by",
		"city_office",
		"state_office",
		"city_registration",
		"dop",
		"dor",
		"grandFather_FatherSide",
		"grandMother_FatherSide",
		"grandFather_MotherSide",
		"grandMother_MotherSide",
	]

	const [initialize, setInitialize] = useState(false);
	const [obs, set_obs] = useState(0);


	const loadDoc  = async ()  => {
		let bdyq2 = {
			query: "getScanDocumentsNotary",
			params: {
				":customerId" : getStore(qryKClient()).clientNotaryId,
				":documentType": "BCT"
			},
			queryString: "customerId contain :customerId AND documentType contain :documentType",
		};

		const res = fetchEncryptStream(bdyq2);
		const td = await res;

		if (td && !td.error) {

				let docId = ObjectKeys(td)[0];

				if(td[docId]){
					updStore(frmNm, td[docId]);
					updStore(frmNm + "_bck", JSON.parse(JSON.stringify(td[docId])));
					set_obs(gen16CodeId())
				}
				else{
					updStore(frmNm, null);
					set_obs(gen16CodeId())
				}
			
		}

	}


	
	useEffect(() => {
		if (!initialize) {
			
			setInitialize(true);
			updStore(frmNm, null);
			set_obs(gen16CodeId());

			setTimeout(() => {
				loadDoc();
				
				set_obs(gen16CodeId())
			}, 50);
			return () => {
				updStore(frmNm, null);
			}; 
		}
	});

	const updFrm = (f, v) => {
		let frm2 = getStore(frmNm) || {};
		frm2[f] = v;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};



	const save  = async ()  => {

		let ffm =  getStore(frmNm);

		let bdyq2 = {};
		if(ffm["documentNotaryId"]){
			let diff = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
		
			bdyq2 = {
				query: "updateDocumentsNotary",
				params:{
					"documentNotaryId": ffm["documentNotaryId"]
				},
				data2update: diff.data
			};
		}
		else{
			ffm["customerId"] = getStore(qryKClient()).clientNotaryId;
			ffm["documentType"] = "BCT";
			ffm["documentNotaryId"] = gen16CodeId();
			bdyq2 = {
				query: "addDocumentsNotary",
				form:ffm
			};
		}

		// * Class B Automovile (Mar 2010), C: Truck over 7500KG (Jun 2014)
	
		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && !td.error) {
			updStore(frmNm, td);
			set_obs(gen16CodeId());
			close();
		}
	}



	
	const print  = async ()  => {

		let ffm = {...getStore(frmNm)};
		let user = {...getStore(qryKClient())};


		ffm.dob =	user?.dob;
		ffm.dateOfBirth = user?.dateOfBirth;
		ffm.name =	txtOrempty(user?.firstName) + txtOrempty(user?.middleName) +  txtOrempty(user?.lastName);
		ffm.ss = user?.ss;
		ffm.genre = user?.genre;

		ffm.city_pob = txtOrempty(user?.placeOfBirth?.city);
		ffm.state_pob = txtOrempty(user?.placeOfBirth?.state);


		if(user?.fatherInfo?.firstName){
			ffm["fatherBirthPlace"]= txtOrempty(user?.fatherInfo?.placeOfBirth?.city) +","+ txtOrempty(user?.fatherInfo?.placeOfBirth?.state);
			ffm["fatherName"]=	txtOrempty(user?.fatherInfo?.firstName)  + txtOrempty(user?.fatherInfo?.middleName) +  txtOrempty(user?.fatherInfo?.lastName);
		} 
		
		if(user?.motherInfo?.firstName){
			ffm["motherBirthPlace"]= txtOrempty(user?.motherInfo?.placeOfBirth?.city) +","+ txtOrempty(user?.motherInfo?.placeOfBirth?.state);
			ffm["motherName"]=	txtOrempty(user?.motherInfo?.firstName)  + txtOrempty(user?.motherInfo?.middleName) +  txtOrempty(user?.motherInfo?.lastName);
		}

		
		let gF_Fs = txtOrempty(ffm["grandFather_FatherSide"]);
		let gM_Fs = txtOrempty(ffm["grandMother_FatherSide"]);
		
		
		let gF_Ms = txtOrempty(ffm["grandFather_MotherSide"]);
		let gM_Ms = txtOrempty(ffm["grandMother_MotherSide"]);
		
		let has2gF = gF_Fs && gM_Fs ? " and":"";
		let has2gM = gF_Ms && gM_Ms? " and":"";
		
		ffm["grands_FatherSide"] = gF_Fs + has2gF + gM_Fs;
		ffm["grands_MotherSide"] = gF_Ms + has2gM + gM_Ms;

		
		
		if(ffm["dor"]){
			let nd = (new Date(ffm["dor"])).getTime();
			if(nd){
				ffm["dor_p"] = parseDate(nd);
			}
		}

		if(ffm["dop"]){
			let nd = (new Date(ffm["dop"])).getTime();
			if(nd){
				ffm["dop_p"] = parseDate(nd);
			}
		}

		if(ffm["dateOfBirth"]){
			ffm["dob_p"] = parseDate(ffm["dateOfBirth"]);
		}
		
		ffm["todayDate"] =  parseDateMMDDYYYY((new Date()).getTime());

		

		let pdfUri = await generateTranslateBirthCertification(ffm, true, true);
		window.open(pdfUri);
	};



	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}
	
	let validSv = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
	

	

	return(
		<div style={{
			maxHeight: "80vh",
			width: "820px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title">
					Traducion de Certificacion de Nacimiento
				</p>
				<div className="flexSpace"/>
				<div className="card">
						<GrayButton label={"Imprimir"} clickHandler={print}/>
					
				</div>
			</div>
			
			
			
			
			<p className="group_title">
				Lugar y datos del Registro 
			</p>
		

			<div className="_dsplFlx spaceAround"> 
				<TextInput  init={getStore(frmNm)?.["folio"]} label={"Folio"} width={90} updChanges={(e)=>updFrm("folio",e)}/>
				<TextInput  init={getStore(frmNm)?.["tomo"]} label={"Tomo"} width={90} updChanges={(e)=>updFrm("tomo",e)}/>
				<DateCalComponent  
					init={getStore(frmNm)?.["dor"]} 
					label={"Fecha de registro"}
					updDate={(e)=>updFrm("dor",e)}
				/>
			</div>
			<div className="_dsplFlx spaceAround"> 
				<TextInput  init={getStore(frmNm)?.["city_registration"]} label={"Municipio"} width={240} updChanges={(e)=>updFrm("city_registration",e)}/>
				<TextInput  
					init={getStore(frmNm)?.["state_registration"]} 
					label={"Provincia"} width={240} 
					updChanges={(e)=>updFrm("state_registration",e)}
				/>
			</div>
			<div className="separator"/>
			
			<p className="group_title">
				Oficina donde se solitito el Registro 
			</p>
			<div className="_dsplFlx spaceAround "> 
				<DateCalComponent  
					init={getStore(frmNm)?.["dop"]} 
					label={"Fecha de solicitud"} 
					updDate={(e)=>updFrm("dop",e)}
				/>
				<TextInput  init={getStore(frmNm)?.["city_office"]} label={"Municipio"} width={240} updChanges={(e)=>updFrm("city_office",e)}/>
				<TextInput  init={getStore(frmNm)?.["state_office"]} label={"Provincia"} width={240} updChanges={(e)=>updFrm("state_office",e)}/>
			</div>
			<div className="_dsplFlx spaceAround flxWrp" style={{margin: "22px 0 12px"}}> 
				
				
				<PickRegisterAgent 
					init={getStore(frmNm)?.["prepared_by"]}
					fld={"prepared_by"}
					title={"Preparado por:"}
					updKey={updFrm}
				/>

				<PickRegisterAgent 
					init={getStore(frmNm)?.["revised_by"]}
					fld={"revised_by"}
					title={"Revisado por:"}
					updKey={updFrm}
				/>
		
				<PickRegisterAgent 
					init={getStore(frmNm)?.["registration_officer"]}
					fld={"registration_officer"}
					title={"Firmado por:"}
					updKey={updFrm}
				/>
				
			</div>
			

			
			<div className="separator"/>

			<p className="group_title">
				Nombre Abuelos Paternos
			</p>
				<div className="_dsplFlx spaceAround"> 
				<TextInput 
					init={getStore(frmNm)?.["grandFather_FatherSide"]} 
					label={"Abuelo"} 
					width={160} 
					updChanges={(e)=>updFrm("grandFather_FatherSide",e)}
				/>
				<div style={{margin: "0 4px"}}></div>
				<TextInput 
					init={getStore(frmNm)?.["grandMother_FatherSide"]} 
					label={"Abuela"} 
					width={160} 
					updChanges={(e)=>updFrm("grandMother_FatherSide",e)}
				/>
			</div>
			<p className="group_title">
				Nombre Abuelos Maternos
			</p>
				<div className="_dsplFlx spaceAround"> 
				<TextInput 
					init={getStore(frmNm)?.["grandFather_MotherSide"]} 
					label={"Abuelo"} 
					width={160} 
					updChanges={(e)=>updFrm("grandFather_MotherSide",e)}
				/>

				<div style={{margin: "0 4px"}}></div>
				<TextInput 
					init={getStore(frmNm)?.["grandMother_MotherSide"]} 
					label={"Abuela "} 
					width={160} 
					updChanges={(e)=>updFrm("grandMother_MotherSide",e)}
				/>
			</div>





			{validSv?.hasChange ? (
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={"Actualizar"} clickHandler={save}/>
						
					</div>
				</div>
			):<div className="card"/>}


		</div>
	)

}



export default TranslateBirthCertificate;








