const RegisterAgentDropD  = ({ init, emptyLabel, onSelect }) => {

	const [list, setList] = useState([]);

	const parseD =  (v) => {
		let nA = []
		v && ObjectKeys(v).map(cl=>{
			let fullNm = txtOrempty(v[cl]?.name);
			nA.push({id:cl, label: fullNm });
		});
		setList(sortByName(nA,"name"));
	}

	const fetch =  (v) => {
		search_notaryAgent(v, parseD);

	}

	const clear =  () => {
		setList([]);
	}



	return (
		<div style={{minWidth: 260}}>
			<DropDwnSearchPicker
				lbl_empty={init || emptyLabel} 
				list={list}
				onSelect={(e)=>onSelect(e)} 
				background={"var(--dark-900)"}
				color={"var(--primary)"}
				callempty={clear}
				fetchData={fetch}
			/>
		</div>
	)

}





const PickRegisterAgent  = ({updKey, title, init,  confirm, fld }) => {

	const [show, setShow] = useState(false);
	const [addview, setAddview] = useState(false);
	const [name, setName] = useState("false");

	const select  =  (e)  => {
		updKey(fld, e.label);
		setShow(false);
	};



	const save = async() => {
        if(addview){
            let nnfrm = {name: name, notaryAgentId: gen16CodeId()};
            let bdyq2 = {...getStore(qryStore())?.add_notaryAgn};
			bdyq2.params = {
				businessId:  getStore(qryKprofile())?.businessId
			}
            bdyq2.form=nnfrm;
            const res = fetchEncryptStream(bdyq2);
			const td = await res;
			if (td && !td.error) {
                confirm && confirm(name);
             //   data?.modalID && CloseModal({id:data?.modalID});
            }
            
        }else{
            confirm && confirm(name);
           // data?.modalID && CloseModal({id:data?.modalID});
        }
	};


	return (
		<div className="_dsplFlx " >
			<div className="flexSpace"/>
			{show ?
			<div className="client_item_box gWXAaj jlytmu">
				<div className="_dsplFlx " >
				
					<div className="_dsplFlx dtls header_card">
						<div className="lbl_h_dtls"  onClick={()=>setShow(!show)}>
							{title} 
						</div>
						
					</div>
					<div className="flexSpace"/>
					<RegisterAgentDropD
						onSelect={select}
					/>
				</div>	
			</div>	
			:		
			<div style={{padding: "0 9px"}}  onClick={()=>setShow(!show)}>
				
			
				<p className="label">
				{title}
				</p>
				<div className="date2Upd notary_agent">
				{txtOrempty(init)}
				</div>
			</div>
			}
		</div>

	)

}

